func solve(sx int64, sy int64, x int64, y int64) int64 {
    a, b := x, y
    count := int64(0)
    for a > 0 && b > 0 {
        if a == sx && b == sy {
            return count
        }
        if a == b {
            break
        }
        if a > b {
            if a >= 2*b {
                if a % 2 == 0 {
                    a = a / 2
                    count++
                } else {
                    break
                }
            } else {
                if a - b < sx {
                    return -1
                }
                a = a - b
                count++
            }
        } else {
            if b >= 2*a {
                if b % 2 == 0 {
                    b = b / 2
                    count++
                } else {
                    break
                }
            } else {
                if b - a < sy {
                    return -1
                }
                b = b - a
                count++
            }
        }
    }
    if a == sx && b == sy {
        return count
    }
    if a == sx + max(sx, sy) && b == sy {
        return count + 1
    }
    if b == sy + max(sx, sy) && a == sx {
        return count + 1
    }
    return -1
}

func max(x, y int64) int64 {
    if x > y {
        return x
    }
    return y
}
